module decoder_3to8 (  
    input [2:0] in,  
    output reg [7:0] disable  
);  
    always @(*) begin  
        disable = 8'b00000000;  
        case (in)  
            3'b000: disable[0] = 1;  
            3'b001: disable[1] = 1;  
            3'b010: disable[2] = 1;  
            3'b011: disable[3] = 1;  
            3'b100: disable[4] = 1;  
            3'b101: disable[5] = 1;  
            3'b110: disable[6] = 1;  
            3'b111: disable[7] = 1;  
        endcase  
    end  
endmodule
